ll pre[N][26], suf[N][26], sum[3][N][26];
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	string s; cin >> s; s = ' ' + s;
	fa(i, 1, n) {
		fa(j, 0, 25)pre[i][j] = pre[i - 1][j];
		pre[i][s[i] - 'a']++;
	}
	fb(i, n, 1) {
		fa(j, 0, 25)suf[i][j] = suf[i + 1][j];
		suf[i][s[i] - 'a']++;
	}
	fa(i, 2, n - 1)fa(j, 0, 25)sum[0][i][j] = sum[0][i - 1][j] + pre[i - 1][j] * suf[i + 1][j];
	fa(i, 2, n - 1)fa(j, 0, 25)sum[1][i][j] = sum[1][i - 1][j] + pre[i - 1][j];
	fa(i, 2, n - 1)fa(j, 0, 25)sum[2][i][j] = sum[2][i - 1][j] + suf[i + 1][j];

	while (m--) {
		int l, r, x; cin >> l >> r >> x;
		if (x == 1)cout << r - l + 1 << endl;
		else if (x == 2) {
			ll ans = 0;
			fa(j, 0, 25) {
				ll cnt = pre[r][j] - pre[l - 1][j];
				ans += cnt * (cnt - 1) / 2;
			}
			cout << ans << endl;
		}
		else {
			if (r - l + 1 < 3) {
				cout << 0 << endl;
				continue;
			}
			ll ans = 0;
			fa(j, 0, 25)ans += sum[0][r - 1][j] - sum[0][l][j];
			fa(j, 0, 25)ans -= (sum[1][r - 1][j] - sum[1][l][j]) * suf[r + 1][j];
			fa(j, 0, 25)ans -= (sum[2][r - 1][j] - sum[2][l][j]) * pre[l - 1][j];
			fa(j, 0, 25)ans += suf[r + 1][j] * pre[l - 1][j] * (r - l - 1);
			cout << ans << endl;
		}
	}
	return;
}
